from typing import List, Tuple

def get_sales_summary_by_group(db_cursor, group_by_column: str) -> List[Tuple[str, float]]:
    allowed_columns = ("product_category", "region")
    if group_by_column not in allowed_columns:
        raise ValueError(
            f"Invalid group by column: {group_by_column}. "
            f"Allowed columns are: {', '.join(allowed_columns)}"
        )

    query = f"""
        SELECT {group_by_column}, SUM(sale_amount) AS total_sales 
        FROM sales_orders 
        GROUP BY {group_by_column}
    """
    db_cursor.execute(query)
    return db_cursor.fetchall()
